SELECT COUNT(DISTINCT PB.PK) AS QUANTIDADE FROM LATTES_PRODBIB PB JOIN LATTES_P_PRODBIB PBP ON PBP.FK_PRODBIB = PB.PK JOIN SERVIDOR S ON S.PK_SIAPE = PBP.FK_SIAPE WHERE CAST(CAST(COALESCE(PB.ANO,'') AS INTEGER) AS TEXT) = '2021' AND (LOWER(PB.NATUREZA) LIKE LOWER('%livro organizado%') OR LOWER(PB.NATUREZA) LIKE LOWER('%edicao%') OR LOWER(PB.TIPO) LIKE LOWER('%livro organizado%') OR LOWER(PB.TIPO) LIKE LOWER('%edicao%')) AND (LOWER(S.SIGLA_CAMPUS) = LOWER('luz') OR LOWER(COALESCE(S.CAMPUS_ATUAL,'')) LIKE '%luzi%') AND (LOWER(COALESCE(S.AREA_INGRESSO,'')) LIKE '%ciencia da computacao%')